{{ {{{|safesubst:}}}#invoke:Unsubst||date=__DATE__ |$B=
<!--{{Unreliable sources}} begin-->{{Ambox
| name  =  Unreliable sources
| subst = <includeonly>{{subst:substcheck}}</includeonly>
| type  = content
| small = {{{small|}}}
| class = ambox-unreliable_sources
| image = [[File:Text document with red question mark.svg|50x40px]]
| issue = {{yesno|{{{some|yes}}}|yes=Some|no=All}} of this {{{1|article}}}'s [[Wikipedia:citing sources|listed sources]] '''may not be [[Wikipedia:Reliable sources|reliable]]'''. {{#ifeq:{{{imdb|}}}|yes|It includes attribution to IMDb, which may not be a reliable source for information.}}
| fix   = Please help improve this article by looking for better, more reliable sources. Unreliable citations may be challenged and removed.
| date  = {{{date|}}}
| cat   = Articles lacking reliable references
| all   = All articles lacking reliable references
|removalnotice = yes
}}<!--{{Unreliable sources}} end-->
}}<noinclude>{{Documentation}}</noinclude>

